# List all available variables from previous tool calls
import sys
import json

print("ALL LOCAL VARIABLES:")
for name, value in sorted(locals().items()):
    if not name.startswith('_'):
        print(f"  {name}: {type(value).__name__}")

print("\nLooking for query results...")
for name, value in locals().items():
    if 'query' in name and ('db' in name or 'db_' in name):
        print(f"Found: {name} = {type(value)}")
        if hasattr(value, '__len__') and not isinstance(value, str):
            print(f"  Length: {len(value)}")
        if value and (isinstance(value, list) or isinstance(value, dict)):
            print(f"  Sample: {str(value)[:200]}")

print("__RESULT__:")
print(json.dumps({"status": "checked variables"})

